@* Vertical sidebar navigation for settings sections *@

<nav class="nav nav-pills flex-column settings-sidebar" role="tablist">
    @foreach (var section in Sections)
    {
        <button class="nav-link text-start @(section.Key == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section.Key)"
                role="tab"
                aria-selected="@(section.Key == ActiveSection)">
            <span class="me-2">@section.Icon</span> @section.Label
        </button>
    }
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨")
    ];
}

@using sv_a84c27dac2874f9597062c9f10130954.Services

<div class="settings-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_profile is null)
    {
        <p>Loading...</p>
        return;
    }

    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>

        <div class="col-md-4 text-center">
            <label class="form-label fw-semibold d-block">Avatar</label>
            <div class="avatar-preview mb-2">
                <img src="@_profile.AvatarUrl" alt="Avatar" class="rounded-circle" width="120" height="120" />
            </div>
            <small class="text-muted text-break">@_profile.AvatarUrl</small>
        </div>
    </div>

    <div class="d-flex gap-2 mt-3">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
            Discard Changes
        </button>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span class="me-2">✅</span> Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public UserProfile? Profile { get; set; }
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private bool _saving;
    private bool _showSuccess;
    private CancellationTokenSource? _toastCts;

    protected override void OnParametersSet()
    {
        if (Profile is not null && _profile != Profile)
        {
            _profile = Profile;
            ResetFields();
        }
    }

    private void ResetFields()
    {
        if (_profile is null) return;
        _displayName = _profile.DisplayName;
        _email = _profile.Email;
        _bio = _profile.Bio;
    }

    private async Task SaveAsync()
    {
        if (_profile is null) return;
        _saving = true;
        var updated = _profile with
        {
            DisplayName = _displayName,
            Email = _email,
            Bio = _bio
        };
        await OnSave.InvokeAsync(updated);
        _profile = updated;
        _saving = false;
        await ShowSuccessToast();
    }

    private void Discard() => ResetFields();

    private async Task ShowSuccessToast()
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;
        _showSuccess = true;
        try
        {
            await Task.Delay(3000, token);
            _showSuccess = false;
        }
        catch (TaskCanceledException) { }
    }
}

@using sv_a84c27dac2874f9597062c9f10130954.Services

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h5 class="mb-3">Muted Channels</h5>
    <div class="row mb-4">
        @foreach (var channel in AllChannels)
        {
            <div class="col-md-4 mb-2">
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="ch-@channel"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="ch-@channel">
                        #@channel <span class="text-muted small">@(_mutedChannels.Contains(channel) ? "(muted)" : "")</span>
                    </label>
                </div>
            </div>
        }
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save Preferences
    </button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3">✅ Notification preferences saved!</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs? Prefs { get; set; }
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    // All available channels; in production this would come from a service
    public static readonly List<string> AllChannels =
        ["general", "engineering", "marketing", "random", "announcements", "support"];

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;
    private bool _showSuccess;
    private CancellationTokenSource? _toastCts;

    protected override void OnParametersSet()
    {
        if (Prefs is null) return;
        _emailNotifications = Prefs.EmailNotifications;
        _pushNotifications = Prefs.PushNotifications;
        _weeklyDigest = Prefs.WeeklyDigest;
        _mutedChannels = [.. Prefs.MutedChannels];
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList()
        );
        await OnSave.InvokeAsync(updated);
        _saving = false;
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        _showSuccess = true;
        try { await Task.Delay(3000, _toastCts.Token); _showSuccess = false; }
        catch (TaskCanceledException) { }
    }
}

@* Expandable panel for changing password *@

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         style="cursor: pointer" @onclick="() => _expanded = !_expanded">
        <span class="fw-semibold">🔑 Change Password</span>
        <span>@(_expanded ? "▲" : "▼")</span>
    </div>
    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="alert alert-danger py-2">@_error</div>
            }
            @if (_showSuccess)
            {
                <div class="alert alert-success py-2">✅ Password updated successfully!</div>
            }

            <button class="btn btn-warning" @onclick="SubmitAsync" disabled="@_submitting">
                @if (_submitting) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string _error = "";
    private bool _submitting;
    private bool _showSuccess;

    private async Task SubmitAsync()
    {
        _error = "";
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _error = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _error = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        _submitting = true;
        await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
        _submitting = false;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _showSuccess = true;
    }
}

@* Confirmation dialog for revoking a session *@

@if (Visible && Session is not null)
{
    <div class="modal-backdrop show" @onclick="Cancel"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Device</dt>
                        <dd class="col-sm-8">@Session.Device</dd>
                        <dt class="col-sm-4">Location</dt>
                        <dd class="col-sm-8">@Session.Location</dd>
                        <dt class="col-sm-4">Last Active</dt>
                        <dd class="col-sm-8">@Session.LastActive.ToString("g")</dd>
                    </dl>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_a84c27dac2874f9597062c9f10130954.Services

@* Table listing active sessions with revoke capability *@

@if (Sessions is null || Sessions.Count == 0)
{
    <p class="text-muted">No active sessions.</p>
    return;
}

<div class="table-responsive">
    <table class="table table-hover align-middle">
        <thead class="table-light">
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                var isCurrent = session == Sessions[0];
                <tr>
                    <td>
                        @session.Device
                        @if (isCurrent)
                        {
                            <span class="badge bg-success ms-1">Current</span>
                        }
                    </td>
