@* Confirmation dialog for revoking a session *@

@if (Visible && Session is not null)
{
    <div class="modal-backdrop show" @onclick="Cancel"></div>
    <div class="modal d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke this session?</p>
                    <dl class="row mb-0">
                        <dt class="col-sm-4">Device</dt>
                        <dd class="col-sm-8">@Session.Device</dd>
                        <dt class="col-sm-4">Location</dt>
                        <dd class="col-sm-8">@Session.Location</dd>
                        <dt class="col-sm-4">Last Active</dt>
                        <dd class="col-sm-8">@Session.LastActive.ToString("g")</dd>
                    </dl>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="Confirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@using sv_a84c27dac2874f9597062c9f10130954.Services

@* Table listing active sessions with revoke capability *@

@if (Sessions is null || Sessions.Count == 0)
{
    <p class="text-muted">No active sessions.</p>
    return;
}

<div class="table-responsive">
    <table class="table table-hover align-middle">
        <thead class="table-light">
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                var isCurrent = session == Sessions[0];
                <tr>
                    <td>
                        @session.Device
                        @if (isCurrent)
                        {
                            <span class="badge bg-success ms-1">Current</span>
                        }
                    </td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (!isCurrent)
                        {
                            <button class="btn btn-sm btn-outline-danger"
                                    @onclick="() => RequestRevoke(session)">
                                Revoke
                            </button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

<RevokeSessionDialog Visible="_showDialog"
                     Session="_sessionToRevoke"
                     OnConfirm="ConfirmRevoke"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter, EditorRequired] public List<ActiveSession>? Sessions { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private bool _showDialog;
    private ActiveSession? _sessionToRevoke;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        }
        _showDialog = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showDialog = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

