    <h4 class="mb-4">Security</h4>

    <ChangePasswordPanel OnChangePassword="OnChangePassword" />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <small class="text-muted">
                        @if (Security?.TwoFactorEnabled == true)
                        {
                            <span class="text-success">● Enabled</span>
                        }
                        else
                        {
                            <span class="text-danger">● Disabled</span>
                        }
                    </small>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox"
                           checked="@(Security?.TwoFactorEnabled ?? false)"
                           @onchange="Toggle2FA" />
                </div>
            </div>

            @if (Security?.LastPasswordChange is not null)
            {
                <hr />
                <small class="text-muted">
                    Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </small>
            }
        </div>
    </div>

    <h5 class="mb-3">Active Sessions</h5>
    <ActiveSessionsTable Sessions="Security?.Sessions" OnRevoke="OnRevokeSession" />
</div>

