+            <div class="appearance-preview p-3 rounded border"
+                 style="@PreviewStyle">
+                <h5 style="@PreviewFontStyle">Dashboard</h5>
+                <p style="@PreviewFontStyle" class="@(_compactMode ? "mb-1" : "mb-3")">
+                    This is a preview of how your content will look with the selected settings.
+                </p>
+                <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
+                    <span class="badge bg-primary" style="@PreviewFontStyle">Active</span>
+                    <span class="badge bg-secondary" style="@PreviewFontStyle">Pending</span>
+                    <span class="badge bg-success" style="@PreviewFontStyle">Complete</span>
+                </div>
+                <button class="btn btn-sm btn-outline-primary" style="@PreviewFontStyle" disabled>
+                    Sample Button
+                </button>
+            </div>
+        </div>
+    </div>
+</div>
+
+@code {
+    [Parameter, EditorRequired] public AppearanceSettings? Settings { get; set; }
+    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }
+
+    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];
+
+    private string _theme = "Light";
+    private string _fontSize = "Medium";
+    private string _language = "English";
+    private bool _compactMode;
+    private bool _saving;
+    private bool _showSuccess;
+    private CancellationTokenSource? _toastCts;
+
+    protected override void OnParametersSet()
+    {
+        if (Settings is null) return;
+        _theme = Settings.Theme;
+        _fontSize = Settings.FontSize;
+        _language = Settings.Language;
+        _compactMode = Settings.CompactMode;
+    }
+
+    private string PreviewStyle
+    {
+        get
+        {
+            var bg = _theme switch
+            {
+                "Dark" => "background-color: #1e1e2e; color: #cdd6f4;",
+                "System" => "background-color: #f0f0f0; color: #333;",
+                _ => "background-color: #ffffff; color: #212529;"
+            };
+            return bg;
+        }
+    }
+
+    private string PreviewFontStyle => _fontSize switch
+    {
+        "Small" => "font-size: 0.8rem;",
+        "Large" => "font-size: 1.2rem;",
+        _ => "font-size: 1rem;"
+    };
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+        await OnSave.InvokeAsync(updated);
+        _saving = false;
+        _toastCts?.Cancel();
+        _toastCts = new CancellationTokenSource();
+        _showSuccess = true;
+        try { await Task.Delay(3000, _toastCts.Token); _showSuccess = false; }
+        catch (TaskCanceledException) { }
+    }
+}
+

