.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 500px;
}

.settings-nav {
    flex: 0 0 200px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-sidebar .nav-link {
    border-radius: 0.375rem;
    margin-bottom: 0.25rem;
    color: #495057;
    padding: 0.6rem 1rem;
    transition: background-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

::deep .settings-section {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.5rem;
}

::deep .avatar-preview {
    border: 3px solid #dee2e6;
    border-radius: 50%;
    display: inline-block;
    padding: 4px;
}

::deep .appearance-preview {
    min-height: 180px;
    transition: all 0.3s ease;
}

::deep .modal-backdrop.show {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0,0,0,0.5);
    z-index: 1040;
}

::deep .modal.d-block {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 1050;
}

